# ========= Stream-build ready_seq.train.csv from sample_skeleton (memory safe) =========

SKELETON = Path("/home/p_esla/Downloads/ali-ccp-extracted/sample_skeleton_train.csv")  # <- your path
OUT_DIR  = Path("/home/p_esla/Downloads/ali-ccp/work"); OUT_DIR.mkdir(parents=True, exist_ok=True)
OUT_CSV  = OUT_DIR / "ready_seq.train.csv"
MAP_UCSV = OUT_DIR / "uid_map.csv"
MAP_ICSV = OUT_DIR / "iid_map.csv"

assert SKELETON.exists(), f"Missing: {SKELETON}"

# We only need: clk (col 0), user hash (col 3), adgroup_id (col 4)
USECOLS = [0, 3, 4]
NAMES   = ["clk", "user_raw", "adgroup_id"]

# Dictionaries we grow as we stream:
user_map    = {}                 # raw user -> contiguous u
item_map    = {}                 # adgroup_id -> contiguous i
user_offset = defaultdict(int)   # running count (for time_stamp) per u
next_u = 0
next_i = 0

# Initialize output with header
with open(OUT_CSV, "w") as f:
    f.write("u,i,time_stamp,clk\n")

CHUNK = 500_000  # tune for your RAM/IO; 200k–1M is typical

reader = pd.read_csv(
    SKELETON,
    header=None,
    usecols=USECOLS,
    names=NAMES,
    dtype={0: "object", 3: "object", 4: "object"},
    chunksize=CHUNK,
    low_memory=True
)

total_rows = 0
for ci, chunk in enumerate(reader, 1):
    # 1) Coerce types & binarize label
    chunk["clk"] = pd.to_numeric(chunk["clk"], errors="coerce").fillna(0).astype(np.int64)
    chunk["clk"] = (chunk["clk"] > 0).astype("int8")

    # 2) Map user_raw -> contiguous u (vectorized)
    new_users = pd.Index(chunk["user_raw"].unique()).difference(user_map.keys())
    if len(new_users):
        add = {u: (next_u + k) for k, u in enumerate(new_users)}
        user_map.update(add)
        next_u += len(add)
    chunk["u"] = chunk["user_raw"].map(user_map).astype("int64")

    # 3) Map adgroup_id -> contiguous i (vectorized)
    chunk["adgroup_id"] = pd.to_numeric(chunk["adgroup_id"], errors="coerce")
    chunk = chunk.dropna(subset=["adgroup_id"])
    chunk["adgroup_id"] = chunk["adgroup_id"].astype("int64")

    new_items = pd.Index(chunk["adgroup_id"].unique()).difference(item_map.keys())
    if len(new_items):
        add = {int(v): (next_i + k) for k, v in enumerate(new_items)}
        item_map.update(add)
        next_i += len(add)
    chunk["i"] = chunk["adgroup_id"].map(item_map).astype("int64")

    # 4) Monotonic per-user time_stamp = previous_count[u] + within-chunk cumcount
    #    (preserves file order; no global sort needed)
    chunk["ts_local"] = chunk.groupby("u").cumcount().astype("int64")
    # map current offsets
    chunk["ts_offset"] = chunk["u"].map(user_offset).astype("int64")
    chunk["time_stamp"] = chunk["ts_offset"] + chunk["ts_local"]

    # update offsets for next chunk
    counts = chunk["u"].value_counts()
    for u, c in counts.items():
        user_offset[int(u)] += int(c)

    # 5) Keep only minimal columns and write append-only
    out = chunk[["u", "i", "time_stamp", "clk"]].astype({"u":"int32","i":"int32","time_stamp":"int64","clk":"int8"})
    out.to_csv(OUT_CSV, mode="a", header=False, index=False)

    total_rows += len(chunk)
    del chunk, out
    gc.collect()
    if ci % 10 == 0:
        print(f"[chunk {ci}] rows processed: {total_rows:,} | users={len(user_map):,} | items={len(item_map):,}")

# Save maps (optional, useful for decoding back)
pd.DataFrame({"u": range(len(user_map)), "user_raw": pd.Index(user_map).sort_values()}).to_csv(MAP_UCSV, index=False)
pd.DataFrame({"i": range(len(item_map)), "adgroup_id": pd.Index(item_map).sort_values()}).to_csv(MAP_ICSV, index=False)

print(f"\nWrote {OUT_CSV}  | rows={total_rows:,}")
print(f"Users={len(user_map):,}  Items={len(item_map):,}")

