# %% [code] cell 10

def resolve_raw_csv(path_like, prefer_names=("raw_sample.train.csv","raw_sample.csv")) -> str:
    """Return a CSV path. If given a tar.gz or a dir, extract/locate the CSV."""
    p = Path(path_like)
    if p.is_dir():
        # Try preferred filenames first
        for nm in prefer_names:
            cp = p / nm
            if cp.exists():
                return str(cp)
        # Otherwise, any CSV inside
        cs = list(p.rglob("*.csv"))
        assert cs, f"No CSV found inside directory: {p}"
        return str(cs[0])

    # .tar.gz / .tgz: extract then locate CSV
    suff = "".join(p.suffixes[-2:]).lower()
    if suff in [".tar.gz", ".tgz"]:
        outdir = Path("/home/p_esla/Downloads/ali-ccp/auto_extract")
        outdir.mkdir(parents=True, exist_ok=True)
        with tarfile.open(p, "r:gz") as tf:
            tf.extractall(outdir)
        # Prefer raw_sample*.csv if present
        cs = sorted(list(outdir.rglob("raw_sample*.csv")))
        if not cs:
            cs = sorted(list(outdir.rglob("*.csv")))
        assert cs, f"No CSV found after extracting archive: {p}"
        return str(cs[0])

    # Otherwise assume it's already a CSV file
    assert p.suffix.lower() == ".csv", f"RAW_PATH must be a CSV (or dir/tar.gz), got: {p}"
    return str(p)


RAW_PATH = resolve_raw_csv(RAW_PATH)
