# ---- Utility: pack a batch and run the model to get logits + labels ----
@torch.no_grad()
def _make_masked_seq_item_emb(seq_items_t):
    """
    seq_items_t: LongTensor (B, S), with -1 as pad
    returns: (B, S, D) masked embeddings (zeros for pad positions)
    """
    seq_items = seq_items_t.to(device)
    mask = (seq_items >= 0).unsqueeze(-1)                  # (B,S,1)
    seq_items_clamped = seq_items.clamp_min(0)             # -1 → 0 for safe index
    # seq_idx = item_model.map_raw_ids_for_seq(seq_items_clamped)
    seq_item_emb = item_model(seq_items_clamped) * mask    # zero-out pads
    return seq_item_emb

def forward_batch(batch):
    """
    Expects the Ali-CCP dataset tuple:
      seq_items_t, seq_times_t (sec), act_types_t, req_time_t (ms), cand_i_t, label_t
    Returns: logits (B,), labels (B,)
    """
    (seq_items_t, seq_times_t, act_types_t, req_time_t, cand_i_t, label_t) = batch
    B = seq_items_t.size(0)

    seq_item_emb = _make_masked_seq_item_emb(seq_items_t)              # (B,S,D)

    # Candidate item embeddings (current impression)
    cand_ids = cand_i_t.to(device).view(B)
    # cand_idx = item_model.map_raw_ids(cand_ids)

    cand_emb = item_model(cand_ids)                                    # (B,D)

    # We pass action_time in milliseconds to be consistent:
    seq_times_ms = (seq_times_t.to(device))                     # (B,S)
    req_time_ms  = req_time_t.to(device).long()                        # (B,1)

    # Action types
    act_types = act_types_t.to(device)

    # Encoder forward → representation
    enc_out = encoder(
        action_type_seq=act_types,
        item_embedding_seq=seq_item_emb,
        action_time_seq=seq_times_ms,     # already in ms
        request_time=req_time_ms,         # ms
        item_embedding=cand_emb,
    )  # (B, encoder.output_dim)

    logits = ctr_head(enc_out).squeeze(-1)                             # (B,)
    labels = label_t.to(device).squeeze(-1).float()                    # (B,)
    return logits, labels

