# ---- Build TRAIN_TUPLES with minimal negatives, then reweight via TARGET_POS_RATIO ----

# 1) Load subset and sort
df = pd.read_csv(
    RAW_PATH,
    usecols=["u","i","time_stamp","clk"],
    dtype={"u":"int32","i":"int32","time_stamp":"int64","clk":"int8"}
).sort_values(["u","time_stamp"]).reset_index(drop=True)

# 2) Minimal synthetic negatives (k=1) to avoid double distribution shift
SEQ_LEN = int(getattr(encoder.transact_config, "seq_len", 100))
NUM_ITEMS = int(df["i"].max()) + 1
rng = np.random.default_rng(42)

# k = #negatives per positive (use your existing K_TRAIN / K_VAL)
def build_tuples_with_impressions(frame, k, rng, NUM_ITEMS, SEQ_LEN):
    """
    Emits 6-field tuples:
      (seq_items, seq_times_sec, seq_action_types, req_time_ms, cand_item_id, click_label)
    History contains ALL events (impressions & clicks).
    """
    samples = []
    hist = defaultdict(lambda: deque(maxlen=SEQ_LEN))  # store (item, ts_sec, action_type)

    for u, i, t, clk in frame[["u","i","time_stamp","clk"]].itertuples(index=False):
        a = 1 if int(clk) > 0 else 0   # 0=impr, 1=click
        h = hist[int(u)]

        # create a training instance only when current row is a positive (clicked)
        if len(h) >= 1 and a == 1:
            pad = SEQ_LEN - len(h)
            seq_items  = ([-1]*pad) + [it for it,_,_ in h]
            seq_times  = ([0]*pad)  + [ts for _,ts,_ in h]          # seconds here
            act_types  = ([-1]*pad) + [at for *_,at in h]           # 0/1 history

            # positive sample (clicked candidate)
            samples.append((seq_items, seq_times, act_types, int(t)*1000, int(i), 1))

            # k negatives: items not in recent history and not the positive
            excl = {it for it,_,_ in h}; excl.add(int(i))
            n = tries = 0
            while n < k and tries < k*10:
                j = int(rng.integers(0, NUM_ITEMS))
                tries += 1
                if j not in excl:
                    samples.append((seq_items, seq_times, act_types, int(t)*1000, j, 0))
                    excl.add(j); n += 1

        # ALWAYS append current exposure to history (impr or click)
        h.append((int(i), int(t), a))

    return samples

K_TRAIN = 9
TRAIN_TUPLES = build_tuples_with_impressions(df, k=K_TRAIN, rng=np.random.default_rng(42), NUM_ITEMS=NUM_ITEMS, SEQ_LEN=SEQ_LEN)

